using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with the default reflection-based resolver ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() – returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() – probes without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? probeInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → Type = {probeInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> returned false");
}

// 3) TryGetTypeInfo<T>() against a source-gen context that only knows about
//    Person — asking for an unknown type returns false instead of throwing.
var sgOptions = new JsonSerializerOptions();
sgOptions.TypeInfoResolver = SmallContext.Default;

if (sgOptions.TryGetTypeInfo<int[]>(out _))
{
    Console.WriteLine("TryGetTypeInfo<int[]> succeeded (unexpected)");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int[]> returned false — type not in source-gen context");
}

// --- Types ---
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
internal partial class SmallContext : JsonSerializerContext;

